import React, { useState, useEffect, useRef } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { api } from '../api';
import { useToast } from '../hooks/useToast';
import Toast from './Toast';

const RutaSegura = ({ token }) => {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const [origen, setOrigen] = useState({ lat: '', lng: '' });
  const [destino, setDestino] = useState({ lat: '', lng: '' });
  const [rutaAnalizada, setRutaAnalizada] = useState(null);
  const [loading, setLoading] = useState(false);
  const [seleccionandoOrigen, setSeleccionandoOrigen] = useState(false);
  const [seleccionandoDestino, setSeleccionandoDestino] = useState(false);
  const [puntoSeleccionado, setPuntoSeleccionado] = useState(null);
  const { toasts, removeToast, toast } = useToast();

  // Refs para evitar stale closures en el event listener del mapa
  const seleccionandoOrigenRef = useRef(false);
  const seleccionandoDestinoRef = useRef(false);

  const markersRef = useRef([]);
  const routeLayerRef = useRef(null);

  const CARTAGENA_CENTER = [10.3910, -75.4794];

  const puntosInteres = [
    { nombre: 'Centro Histórico', lat: 10.4236, lng: -75.5478 },
    { nombre: 'Bocagrande', lat: 10.3977, lng: -75.5515 },
    { nombre: 'Castillo San Felipe', lat: 10.4232, lng: -75.5412 },
    { nombre: 'Terminal de Buses', lat: 10.3896, lng: -75.5135 },
    { nombre: 'Aeropuerto', lat: 10.4424, lng: -75.5130 },
    { nombre: 'Mercado de Bazurto', lat: 10.4089, lng: -75.5236 },
  ];

  // Sincronizar refs con el estado
  useEffect(() => {
    seleccionandoOrigenRef.current = seleccionandoOrigen;
  }, [seleccionandoOrigen]);

  useEffect(() => {
    seleccionandoDestinoRef.current = seleccionandoDestino;
  }, [seleccionandoDestino]);

  useEffect(() => {
    if (!mapInstanceRef.current && mapRef.current) {
      mapInstanceRef.current = L.map(mapRef.current).setView(CARTAGENA_CENTER, 12);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '© OpenStreetMap contributors',
      }).addTo(mapInstanceRef.current);

      // Usar refs en el click handler para evitar stale closure
      mapInstanceRef.current.on('click', (e) => {
        if (seleccionandoOrigenRef.current) {
          setOrigen({ lat: e.latlng.lat.toFixed(6), lng: e.latlng.lng.toFixed(6) });
          setSeleccionandoOrigen(false);
          agregarMarcador(e.latlng, '🟢 Origen', 'origen');
        } else if (seleccionandoDestinoRef.current) {
          setDestino({ lat: e.latlng.lat.toFixed(6), lng: e.latlng.lng.toFixed(6) });
          setSeleccionandoDestino(false);
          agregarMarcador(e.latlng, '🔴 Destino', 'destino');
        }
      });
    }

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!mapInstanceRef.current) return;
    mapInstanceRef.current.getContainer().style.cursor =
      seleccionandoOrigen || seleccionandoDestino ? 'crosshair' : '';
  }, [seleccionandoOrigen, seleccionandoDestino]);

  const agregarMarcador = (latlng, titulo, tipo) => {
    markersRef.current = markersRef.current.filter((m) => {
      if (m.tipo === tipo) {
        mapInstanceRef.current.removeLayer(m.marker);
        return false;
      }
      return true;
    });

    const icon = L.divIcon({
      className: 'custom-marker',
      html: `<div class="marker-${tipo}">${tipo === 'origen' ? '🟢' : '🔴'}</div>`,
      iconSize: [40, 40],
    });

    const marker = L.marker(latlng, { icon }).addTo(mapInstanceRef.current);
    marker.bindPopup(titulo);
    markersRef.current.push({ marker, tipo });
  };

  const seleccionarPuntoInteres = (punto, tipo) => {
    if (tipo === 'origen') {
      setOrigen({ lat: punto.lat, lng: punto.lng });
      agregarMarcador({ lat: punto.lat, lng: punto.lng }, `🟢 ${punto.nombre}`, 'origen');
    } else {
      setDestino({ lat: punto.lat, lng: punto.lng });
      agregarMarcador({ lat: punto.lat, lng: punto.lng }, `🔴 ${punto.nombre}`, 'destino');
    }
  };

  const analizarRuta = async () => {
    if (!origen.lat || !origen.lng || !destino.lat || !destino.lng) {
      toast.warning('Por favor selecciona origen y destino');
      return;
    }

    setLoading(true);
    try {
      const data = await api.post('/api/rutas/analizar', {
        origen_lat: parseFloat(origen.lat),
        origen_lng: parseFloat(origen.lng),
        destino_lat: parseFloat(destino.lat),
        destino_lng: parseFloat(destino.lng),
      });
      setRutaAnalizada(data);
      dibujarRuta(data);
    } catch (error) {
      toast.error(`Error al analizar ruta: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const dibujarRuta = (data) => {
    if (routeLayerRef.current) mapInstanceRef.current.removeLayer(routeLayerRef.current);

    const latlngs = data.puntos_ruta.map((p) => [p[0], p[1]]);
    routeLayerRef.current = L.polyline(latlngs, {
      color: data.nivel_riesgo_general === 'Alto' ? '#F44336' :
             data.nivel_riesgo_general === 'Medio' ? '#FF9800' : '#4CAF50',
      weight: 5,
      opacity: 0.7,
    }).addTo(mapInstanceRef.current);

    mapInstanceRef.current.fitBounds(routeLayerRef.current.getBounds());

    data.puntos_criticos.forEach((punto) => {
      const icon = L.divIcon({
        className: 'marker-critico',
        html: '<div class="marker-alerta">⚠️</div>',
        iconSize: [35, 35],
      });

      const marker = L.marker([punto.latitud, punto.longitud], { icon }).addTo(mapInstanceRef.current);
      marker.bindPopup(`
        <div class="popup-critico">
          <h4>⚠️ Punto Crítico</h4>
          <p><strong>Tipo:</strong> ${punto.tipo}</p>
          <p><strong>Nivel de riesgo:</strong> ${(punto.nivel_riesgo * 100).toFixed(0)}%</p>
          <p><strong>Distancia:</strong> ${punto.distancia_metros.toFixed(0)}m de la ruta</p>
          <div class="barra-riesgo">
            <div class="barra-fill" style="width: ${punto.nivel_riesgo * 100}%;
                 background: ${punto.nivel_riesgo > 0.7 ? '#F44336' : punto.nivel_riesgo > 0.4 ? '#FF9800' : '#4CAF50'}">
            </div>
          </div>
        </div>
      `);

      markersRef.current.push({ marker, tipo: 'critico' });
    });
  };

  const limpiarRuta = () => {
    setOrigen({ lat: '', lng: '' });
    setDestino({ lat: '', lng: '' });
    setRutaAnalizada(null);
    setPuntoSeleccionado(null);

    markersRef.current.forEach((m) => mapInstanceRef.current.removeLayer(m.marker));
    markersRef.current = [];

    if (routeLayerRef.current) {
      mapInstanceRef.current.removeLayer(routeLayerRef.current);
      routeLayerRef.current = null;
    }
  };

  const getNivelRiesgoColor = (nivel) => {
    if (nivel === 'Alto') return '#F44336';
    if (nivel === 'Medio') return '#FF9800';
    return '#4CAF50';
  };

  return (
    <div className="ruta-segura-container">
      <Toast toasts={toasts} onRemove={removeToast} />

      <div className="panel-ruta">
        <h2>🛣️ Planificador de Ruta Segura</h2>

        <div className="seccion-coordenadas">
          <h3>📍 Origen</h3>
          <div className="input-group">
            <input type="number" step="0.000001" placeholder="Latitud"
              value={origen.lat} onChange={(e) => setOrigen({ ...origen, lat: e.target.value })} />
            <input type="number" step="0.000001" placeholder="Longitud"
              value={origen.lng} onChange={(e) => setOrigen({ ...origen, lng: e.target.value })} />
          </div>
          <button
            className={`btn-seleccionar ${seleccionandoOrigen ? 'active' : ''}`}
            onClick={() => {
              setSeleccionandoOrigen(!seleccionandoOrigen);
              setSeleccionandoDestino(false);
            }}
          >
            {seleccionandoOrigen ? '✋ Cancelar' : '📍 Seleccionar en mapa'}
          </button>
          <div className="puntos-rapidos">
            <small>Puntos rápidos:</small>
            {puntosInteres.slice(0, 3).map((punto, idx) => (
              <button key={idx} className="btn-punto-rapido"
                onClick={() => seleccionarPuntoInteres(punto, 'origen')}>
                {punto.nombre}
              </button>
            ))}
          </div>
        </div>

        <div className="seccion-coordenadas">
          <h3>🎯 Destino</h3>
          <div className="input-group">
            <input type="number" step="0.000001" placeholder="Latitud"
              value={destino.lat} onChange={(e) => setDestino({ ...destino, lat: e.target.value })} />
            <input type="number" step="0.000001" placeholder="Longitud"
              value={destino.lng} onChange={(e) => setDestino({ ...destino, lng: e.target.value })} />
          </div>
          <button
            className={`btn-seleccionar ${seleccionandoDestino ? 'active' : ''}`}
            onClick={() => {
              setSeleccionandoDestino(!seleccionandoDestino);
              setSeleccionandoOrigen(false);
            }}
          >
            {seleccionandoDestino ? '✋ Cancelar' : '📍 Seleccionar en mapa'}
          </button>
          <div className="puntos-rapidos">
            <small>Puntos rápidos:</small>
            {puntosInteres.slice(3, 6).map((punto, idx) => (
              <button key={idx} className="btn-punto-rapido"
                onClick={() => seleccionarPuntoInteres(punto, 'destino')}>
                {punto.nombre}
              </button>
            ))}
          </div>
        </div>

        <div className="acciones-ruta">
          <button className="btn-analizar" onClick={analizarRuta} disabled={loading}>
            {loading ? '🔄 Analizando...' : '🔍 Analizar Ruta'}
          </button>
          <button className="btn-limpiar" onClick={limpiarRuta}>🗑️ Limpiar</button>
        </div>

        {rutaAnalizada && (
          <div className="resultado-ruta">
            <h3>📊 Análisis de Ruta</h3>
            <div className="info-ruta">
              <div className="info-item">
                <span className="label">Distancia:</span>
                <span className="value">{rutaAnalizada.distancia_total_km} km</span>
              </div>
              <div className="info-item">
                <span className="label">Tiempo estimado:</span>
                <span className="value">{rutaAnalizada.tiempo_estimado_min} min</span>
              </div>
              <div className="info-item">
                <span className="label">Nivel de riesgo:</span>
                <span className="value badge" style={{
                  background: getNivelRiesgoColor(rutaAnalizada.nivel_riesgo_general),
                  color: 'white', padding: '4px 12px', borderRadius: '12px',
                }}>
                  {rutaAnalizada.nivel_riesgo_general}
                </span>
              </div>
            </div>

            {rutaAnalizada.puntos_criticos.length > 0 && (
              <div className="puntos-criticos">
                <h4>⚠️ Puntos Críticos ({rutaAnalizada.puntos_criticos.length})</h4>
                <div className="lista-criticos">
                  {rutaAnalizada.puntos_criticos.map((punto, idx) => (
                    <div key={idx} className="punto-critico-item"
                      onClick={() => setPuntoSeleccionado(punto)} style={{ cursor: 'pointer' }}>
                      <div className="punto-header">
                        <span className="punto-numero">#{idx + 1}</span>
                        <span className="punto-tipo">{punto.tipo}</span>
                      </div>
                      <div className="punto-detalles">
                        <p>📍 {punto.distancia_metros.toFixed(0)}m de la ruta</p>
                        <div className="nivel-riesgo-mini">
                          <div className="barra-mini" style={{
                            width: `${punto.nivel_riesgo * 100}%`,
                            background: punto.nivel_riesgo > 0.7 ? '#F44336' :
                                        punto.nivel_riesgo > 0.4 ? '#FF9800' : '#4CAF50',
                          }}></div>
                        </div>
                        <small>Riesgo: {(punto.nivel_riesgo * 100).toFixed(0)}%</small>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {rutaAnalizada.puntos_criticos.length === 0 && (
              <div className="sin-alertas">
                <span>✅</span>
                <p>¡No se detectaron puntos críticos en esta ruta!</p>
              </div>
            )}

            <div className="recomendaciones">
              <h4>💡 Recomendaciones</h4>
              <ul>
                {rutaAnalizada.nivel_riesgo_general === 'Alto' && (
                  <>
                    <li>⚠️ Mantenga velocidad reducida en todo el trayecto</li>
                    <li>👀 Extreme precauciones en los puntos marcados</li>
                    <li>🌧️ Considere esperar si hay lluvia</li>
                  </>
                )}
                {rutaAnalizada.nivel_riesgo_general === 'Medio' && (
                  <>
                    <li>⚡ Conduzca con precaución</li>
                    <li>🚦 Respete las señales de tránsito</li>
                    <li>👁️ Esté atento a los puntos críticos señalados</li>
                  </>
                )}
                {rutaAnalizada.nivel_riesgo_general === 'Bajo' && (
                  <>
                    <li>✅ Ruta segura, mantenga velocidad prudente</li>
                    <li>🚗 Respete límites de velocidad</li>
                    <li>😊 Disfrute su viaje con responsabilidad</li>
                  </>
                )}
              </ul>
            </div>
          </div>
        )}

        {puntoSeleccionado && (
          <div className="detalle-punto-modal" onClick={() => setPuntoSeleccionado(null)}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
              <button className="btn-cerrar" onClick={() => setPuntoSeleccionado(null)}>✕</button>
              <h3>Detalle del Punto Crítico</h3>
              <div className="detalle-completo">
                <p><strong>Coordenadas:</strong></p>
                <p>Lat: {puntoSeleccionado.latitud.toFixed(6)}</p>
                <p>Lng: {puntoSeleccionado.longitud.toFixed(6)}</p>
                <p><strong>Tipo:</strong> {puntoSeleccionado.tipo}</p>
                <p><strong>Distancia de la ruta:</strong> {puntoSeleccionado.distancia_metros.toFixed(0)}m</p>
                <div className="barra-riesgo-detalle">
                  <p><strong>Nivel de riesgo:</strong></p>
                  <div className="barra-contenedor">
                    <div className="barra-fill" style={{
                      width: `${puntoSeleccionado.nivel_riesgo * 100}%`,
                      background: puntoSeleccionado.nivel_riesgo > 0.7 ? '#F44336' :
                                  puntoSeleccionado.nivel_riesgo > 0.4 ? '#FF9800' : '#4CAF50',
                      height: '30px', borderRadius: '5px', transition: 'width 0.3s',
                    }}></div>
                  </div>
                  <p className="porcentaje">{(puntoSeleccionado.nivel_riesgo * 100).toFixed(0)}%</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="mapa-wrapper-ruta">
        <div ref={mapRef} className="mapa" style={{ height: '100%', width: '100%' }} />
        {(seleccionandoOrigen || seleccionandoDestino) && (
          <div className="instruccion-mapa">
            <p>
              {seleccionandoOrigen
                ? '📍 Haz clic en el mapa para seleccionar el ORIGEN'
                : '📍 Haz clic en el mapa para seleccionar el DESTINO'}
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default RutaSegura;
